import React, { useCallback, useMemo } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  IconButton,
  Tooltip
} from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWSkeleton from '../../FAWSkeleton';
import FAWLoader from '../../FAWLoader';
import { SendIcon } from "@diligentcorp/atlas-react-icons/lens";
import FAWDrawer from '../../FAWDrawer';
import FAWToast from '../../FAWToast';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import FAWModal from '../../FAWModal';
import SendTestEmailForm from './SendTestEmailForm';
import { useSendTestEmailState } from '../hooks/useSendTestEmailState';
import { useSendTestEmailHandlers } from '../hooks/useSendTestEmailHandlers';
import '../styles/notifications.css';

const SendTestEmailDrawer = ({ 
  open = false, 
  onClose, 
  onSuccess, 
  notificationData = {},
  selectedNotificationType = null 
}) => {
  // Use custom hooks for state management and handlers
  const state = useSendTestEmailState({ 
    open, 
    onClose, 
    onSuccess, 
    notificationData, 
    selectedNotificationType 
  });
  const handlers = useSendTestEmailHandlers({
    onClose,
    onSuccess,
    notificationData,
    selectedNotificationType,
    formRef: state.formRef,
    setSending: state.setSending,
    setToast: state.setToast,
    setDrawerOpen: state.setDrawerOpen,
    setError: state.setError,
    setConfirmationDialog: state.setConfirmationDialog
  });

  // Define drawer actions with useMemo to prevent unnecessary re-renders
  const drawerActions = useMemo(() => [
    {
      text: 'Cancel',
      variant: 'outlined',
      onClick: handlers.handleCancel,
      disabled: state.sending,
      handlerType: 'custom' // Bypass form submission for custom handlers
    },
    {
      text: state.sending ? 'Sending...' : 'Send Test Email',
      variant: 'contained',
      color: 'primary',
      onClick: handlers.handleSendClick,
      disabled: state.sending,
      handlerType: 'custom', // Bypass form submission for custom handlers
      componentType: 'sendtestemail', // Special identifier for send test email
      startIcon: <SendIcon size="md" />
    }
  ], [handlers.handleCancel, handlers.handleSendClick, state.sending]);

  // Memoize confirmation dialog content and actions to prevent unnecessary re-renders
  const confirmationContent = useMemo(() => (
    <Box sx={{ p: 2 }}>
      <FAWTypography variant="body1">
        {state.confirmationDialog.message}
      </FAWTypography>
    </Box>
  ), [state.confirmationDialog.message]);

  const confirmationActions = useMemo(() => [
    {
      label: state.confirmationDialog.cancelText || 'Cancel',
      onClick: state.confirmationDialog.onCancel,
      variant: 'outlined',
      color: 'secondary'
    },
    {
      label: state.confirmationDialog.confirmText || 'Send',
      onClick: state.confirmationDialog.onConfirm,
      variant: 'contained',
      color: state.confirmationDialog.severity === 'error' ? 'error' : 'primary'
    }
  ], [
    state.confirmationDialog.cancelText,
    state.confirmationDialog.confirmText,
    state.confirmationDialog.onCancel,
    state.confirmationDialog.onConfirm,
    state.confirmationDialog.severity
  ]);

  return (
    <FAWErrorBoundary
      title="Send Test Email Error"
      message="An error occurred while loading the send test email form. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('SendTestEmailDrawer Error:', error, errorInfo);
      }}
      onReportError={(error) => {
        // Error reported by user
      }}
    >
      <Box className="send-test-email-drawer-container">
        {/* Atlas Toast for notifications */}
        <FAWToast 
          className="send-test-email-drawer-toast"
          open={state.toast.open} 
          message={state.toast.message} 
          type={state.toast.type} 
          duration={state.toast.duration}
          onClose={handlers.handleToastClose} 
        />

        {/* Confirmation Dialog */}
        <FAWModal
          open={state.confirmationDialog.open}
          title={state.confirmationDialog.title}
          content={confirmationContent}
          actions={confirmationActions}
          onClose={state.confirmationDialog.onCancel}
        />

        {/* Main Drawer - Contains the form for sending test email */}
        <FAWDrawer
          className="send-test-email-drawer"
          open={state.drawerOpen}
          onClose={handlers.handleCloseDrawer}
          title="Send Test Email"
          width={400}
          anchor="right"
          variant="temporary"
          showCloseButton={true}
          showHeader={true}
          customFooter={true}
          actions={drawerActions}
        >
          <Box sx={{ position: 'relative', height: '100%' }}>
            {/* Sending overlay */}
            {state.sending && (
              <Box
                sx={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  backgroundColor: 'rgba(255, 255, 255, 0.8)',
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'center',
                  zIndex: 10,
                  backdropFilter: 'blur(2px)'
                }}
              >
                <FAWLoader size={40} label="Sending..." />
              </Box>
            )}
            
            {state.loading ? (
              <Box className="send-test-email-drawer-loading" sx={{ p: 3 }}>
                <FAWSkeleton variant="form" />
              </Box>
            ) : (
              <SendTestEmailForm
                ref={state.formRef}
                onSend={handlers.handleSendClick}
                onCancel={handlers.handleCancel}
                initialData={state.initialData}
                sending={state.sending}
                notificationData={notificationData}
                selectedNotificationType={selectedNotificationType}
              />
            )}
          </Box>
        </FAWDrawer>
      </Box>
    </FAWErrorBoundary>
  );
};

export default SendTestEmailDrawer;
