import { useState, useEffect, useCallback, useRef } from 'react';

/**
 * Custom hook for managing SendTestEmailDrawer state
 * Extracts all state management logic to make the component more modular
 */
export const useSendTestEmailState = ({ 
  open, 
  onClose, 
  onSuccess, 
  notificationData, 
  selectedNotificationType 
}) => {
  // Core state
  const [drawerOpen, setDrawerOpen] = useState(open);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  const [sending, setSending] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  
  // Form and data state
  const formRef = useRef(null);
  const [initialData, setInitialData] = useState({
    RecipientEmail: ''
  });
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Send',
    cancelText: 'Cancel',
    severity: 'info'
  });

  // Sync drawer state with external prop
  useEffect(() => {
    setDrawerOpen(open);
  }, [open]);

  // Initialize data when component mounts or notification data changes
  useEffect(() => {
    if (notificationData && selectedNotificationType) {
      setInitialData({
        RecipientEmail: ''
      });
    }
  }, [notificationData, selectedNotificationType]);

  // Show toast notification
  const showToast = useCallback((message, type = 'info', duration = 3000) => {
    setToast({ open: true, message, type, duration });
  }, []);

  // Hide toast notification
  const hideToast = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, []);

  // Show confirmation dialog
  const showConfirmation = useCallback((title, message, onConfirm, options = {}) => {
    setConfirmationDialog({
      open: true,
      title,
      message,
      onConfirm,
      onCancel: () => setConfirmationDialog(prev => ({ ...prev, open: false })),
      confirmText: options.confirmText || 'Send',
      cancelText: options.cancelText || 'Cancel',
      severity: options.severity || 'info'
    });
  }, []);

  // Hide confirmation dialog
  const hideConfirmation = useCallback(() => {
    setConfirmationDialog(prev => ({ ...prev, open: false }));
  }, []);

  return {
    // State
    drawerOpen,
    setDrawerOpen,
    toast,
    setToast,
    sending,
    setSending,
    loading,
    setLoading,
    error,
    setError,
    initialData,
    setInitialData,
    confirmationDialog,
    setConfirmationDialog,
    formRef,
    
    // Actions
    showToast,
    hideToast,
    showConfirmation,
    hideConfirmation
  };
};
