import React, { forwardRef, useImperativeHandle, useState, useEffect } from 'react';
import { Box } from '@mui/material';
import FAWInput from '../../FAWInput';
import FAWTypography from '../../FAWTypography';
import '../styles/notifications.css';

const SendTestEmailForm = forwardRef(({
  onSend,
  onCancel,
  initialData = {},
  sending = false,
  notificationData = {},
  selectedNotificationType = null
}, ref) => {
  const [formData, setFormData] = useState({
    RecipientEmail: initialData.RecipientEmail || ''
  });

  const [errors, setErrors] = useState({});

  // Update form data when initialData changes
  useEffect(() => {
    setFormData({
      RecipientEmail: initialData.RecipientEmail || ''
    });
  }, [initialData]);

  // Expose methods to parent component
  useImperativeHandle(ref, () => ({
    getFormData: () => formData,
    validateForm: () => {
      const newErrors = {};
      
      if (!formData.RecipientEmail || formData.RecipientEmail.trim() === '') {
        newErrors.RecipientEmail = 'Recipient Email is required';
      } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.RecipientEmail)) {
        newErrors.RecipientEmail = 'Please enter a valid email address';
      }
      
      setErrors(newErrors);
      return Object.keys(newErrors).length === 0;
    },
    resetForm: () => {
      setFormData({
        RecipientEmail: ''
      });
      setErrors({});
    }
  }));

  const handleInputChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
    
    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (onSend) {
      onSend();
    }
  };

  return (
    <Box className="send-test-email-form" sx={{ p: 3, position: 'relative' }}>
      <form onSubmit={handleSubmit}>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
          <FAWInput
            name="RecipientEmail"
            label="Recipient Email"
            placeholder="Enter recipient email address"
            value={formData.RecipientEmail}
            onChange={(e) => handleInputChange('RecipientEmail', e.target.value)}
            required
            fullWidth
            error={!!errors.RecipientEmail}
            helperText={errors.RecipientEmail}
            disabled={sending}
            labelSx={{
              fontSize: '14px',
              fontWeight: 500
            }}
          />
        </Box>
      </form>
    </Box>
  );
});

SendTestEmailForm.displayName = 'SendTestEmailForm';

export default SendTestEmailForm;
