import { useCallback } from 'react';

/**
 * Custom hook for managing SendTestEmailDrawer handlers
 * Extracts all handler logic to make the component more modular
 */
export const useSendTestEmailHandlers = ({
  onClose,
  onSuccess,
  notificationData,
  selectedNotificationType,
  formRef,
  setSending,
  setToast,
  setDrawerOpen,
  setError,
  setConfirmationDialog
}) => {

  // Handle drawer close
  const handleCloseDrawer = useCallback(() => {
    setDrawerOpen(false);
    if (onClose) {
      onClose();
    }
  }, [onClose, setDrawerOpen]);

  // Handle cancel action
  const handleCancel = useCallback(() => {
    handleCloseDrawer();
  }, [handleCloseDrawer]);

  // Handle toast close
  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, [setToast]);

  // Handle send test email
  const handleSendClick = useCallback(async () => {
    try {
      setError(null);

      // Get form data using the form component's exposed methods
      let formData = {};
      if (formRef.current && formRef.current.getFormData) {
        formData = formRef.current.getFormData();
      }

      // Use form's built-in validation (shows inline errors)
      if (formRef.current && formRef.current.validateForm) {
        const isValid = formRef.current.validateForm();
        if (!isValid) {
          return; // Form validation will show inline errors
        }
      }

      // Check recipient email
      const recipientEmail = formData['RecipientEmail'];
      if (!recipientEmail || recipientEmail.trim() === '') {
        setToast({
          open: true,
          message: 'Recipient Email Address is required',
          type: 'error',
          duration: 30000
        });
        return;
      }

      // Validate email format - improved regex to support modern TLDs and special cases
      // Supports: user@domain.com, user.name+tag@domain.co.uk, etc.
      const emailRegex = /^[a-zA-Z0-9.!#$%&'*+\/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$/;
      if (!emailRegex.test(recipientEmail)) {
        setToast({
          open: true,
          message: 'Please enter a valid recipient email address',
          type: 'error',
          duration: 30000
        });
        return;
      }

      // Check notification type and data
      if (!selectedNotificationType?.value || !notificationData || Object.keys(notificationData).length === 0) {
        setToast({
          open: true,
          message: 'Please select a notification type and wait for content to load',
          type: 'warning',
          duration: 30000
        });
        return;
      }

      setSending(true);

      // Prepare the payload matching NotificationDefinitionModel structure
      // This matches what $('form').serialize() would send from the legacy implementation
      const payload = {
        SelectedNotificationDefinitionType: selectedNotificationType?.value || '',
        SelectedTemplateLanguage: notificationData?.SelectedTemplateLanguage || notificationData?.language || 'EN',
        SelectedScheduleTypes: notificationData?.SelectedScheduleTypes || notificationData?.scheduleFrequency || 'Run Only Once',
        SubjectContent: notificationData?.SubjectContent || notificationData?.subject || '',
        MessageContent: notificationData?.MessageContent || notificationData?.message || '',
        ActiveIn: notificationData?.ActiveIn || (notificationData?.isActive !== false ? 'true' : 'false'),
        CanFrequencyChange: notificationData?.CanFrequencyChange || 'False',
        TestEmailRecipientEmailAddress: recipientEmail,
        ExistingNotificationTypeNamesJson: '[]',
        'notification-type-name': ''
      };

      // Make AJAX call to send test email using GET with query parameters
      const queryParams = new URLSearchParams(payload);
      const url = `/Notification/TestNotificatonTemplate?${queryParams.toString()}`;
      
      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json; charset=utf-8',
        }
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();
      
      if (result.IsSuccess) {
        setToast({
          open: true,
          message: result.Message || 'Test email sent successfully! Please check your email.',
          type: 'success',
          duration: 30000
        });
        
        // Close drawer after successful send
        setTimeout(() => {
          handleCloseDrawer();
        }, 1000); // Small delay so user can see success message
        
        // Call success callback if provided
        if (onSuccess) {
          onSuccess(result);
        }
      } else {
        setToast({
          open: true,
          message: result.Message || 'Failed to send test email',
          type: 'error',
          duration: 30000
        });
      }

    } catch (error) {
      console.error('Error sending test email:', error);
      setToast({
        open: true,
        message: 'Error sending test email. Please try again or contact support.',
        type: 'error',
        duration: 30000
      });
      setError(error.message);
    } finally {
      setSending(false);
    }
  }, [
    formRef,
    selectedNotificationType,
    notificationData,
    setSending,
    setToast,
    setError,
    handleCloseDrawer,
    onSuccess
  ]);

  return {
    handleCloseDrawer,
    handleCancel,
    handleSendClick,
    handleToastClose
  };
};
